const express = require('express');
const winston = require('winston');
const morgan = require('morgan');

const app = express();

// Set up request logging with Winston and Morgan
app.use(morgan('combined', { stream: winston.stream }));

// Define a custom log format for user-provided data
winston.format((info) => {
  const { username, ipAddress, customHeaders } = info;
  return `${username} (${ipAddress}) ${customHeaders}`;
});

// Accept user input and write it directly to log files
app.post('/log', (req, res) => {
  const { message } = req.body;
  winston.info(message);
  res.send('Logged');
});